        var lastState;

        builder.onGridChange(function(state) {
            calls += 1;
            lastState = state;
        });

        builder.toggleWall(1, 1);
        builder.placeStart(0, 1);

        calls.should.equal(2);
        lastState.start.should.eql({ x: 0, y: 1 });
        lastState.grid[1][1].should.equal(1);
    });

    it('should reject invalid matrices in setGrid', function() {
        var builder = createScenarioBuilder();

        (function() {
            builder.setGrid([]);
        }).should.throw();

        (function() {
            builder.setGrid([[0, 1], [1]]);
        }).should.throw();

