:root {
  --walkable: #f4f6f6;
  --wall: #273043;
  --start: #2f9e44;
  --end: #d9480f;
  --explored: #94d2bd;
  --path: #ffd166;
  --grid-border: #c3ccd6;
  --bg: #eef1f4;
  --text: #20262e;
  --panel: #ffffff;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: linear-gradient(160deg, #edf2f8 0%, #e8eee9 100%);
  color: var(--text);
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
}

.scenario-app {
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.app-header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
}

h1,
h2 {
  margin: 0;
}

.controls-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 8px;
}

label {
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 14px;
}

input,
select,
textarea,
button {
  font: inherit;
}

.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

button {
  border: 1px solid #8c8c8c;
  background: #ffffff;
  color: #222;
  border-radius: 6px;
  padding: 7px 10px;
  cursor: pointer;
}

button.is-active {
  background: #1f2933;
  color: #fff;
}

.workspace {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 320px;
  gap: 12px;
  align-items: start;
}

.panel {
  background: var(--panel);
  border: 1px solid #d8dde3;
  border-radius: 8px;
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.grid {
  width: min(92vw, 760px);
  aspect-ratio: 1 / 1;
  display: grid;
  border: 1px solid var(--grid-border);
  background: #ffffff;
}

.cell {
  border: 1px solid #d5d9de;
  background: var(--walkable);
  cursor: pointer;
}

.cell.wall {
  background: var(--wall);
}

.cell.start {
  background: var(--start);
}

.cell.end {
  background: var(--end);
}

.cell.explored {
  background: var(--explored);
}

.cell.path {
  background: var(--path);
}

.metrics {
  display: grid;
  gap: 6px;
}

.metric {
  display: flex;
  justify-content: space-between;
  border: 1px solid #dce2e8;
  border-radius: 6px;
  padding: 6px 8px;
}

.action-row {
  display: flex;
  gap: 8px;
