                '<div class="metric-line"><span>Path</span><strong>' + run.metrics.pathLength + '</strong></div>' +
                '<div class="metric-diff">Δ ' + (diff.pathLength >= 0 ? '+' : '') + diff.pathLength + '</div>' +
                '<div class="metric-line"><span>Time</span><strong>' + run.metrics.timeMs + ' ms</strong></div>' +
