(function(root, factory) {
    if (typeof module === 'object' && module.exports) {
        module.exports = factory(
            require('../../src/PathFinding'),
            require('./scorer'),
            require('./persistence')
        );
    } else {
        root.createScenarioRuntime = factory(
            root.PF,
            root.ScenarioScorer,
            root.ScenarioPersistence
        );
    }
}(this, function(defaultPF, defaultScorer, defaultPersistence) {
    'use strict';

    function clone(value) {
        if (value === undefined) {
            return undefined;
        }
        return JSON.parse(JSON.stringify(value));
    }

    function key(x, y) {
        return x + ',' + y;
    }

    function createMatrix(width, height) {
        var matrix = [];
        for (var y = 0; y < height; y += 1) {
            var row = [];
            for (var x = 0; x < width; x += 1) {
                row.push(0);
            }
            matrix.push(row);
        }
        return matrix;
    }

    function createFinder(PF, algorithmName) {
        var Finder = PF[algorithmName];

        if (typeof Finder !== 'function') {
            throw new Error('Unknown algorithm: ' + algorithmName);
        }

        return new Finder();
    }

    function collectExploredNodes(grid, path) {
        var nodes = grid.nodes;
        var explored = [];
        var pathLookup = {};
        var y;
        var x;

        (path || []).forEach(function(point) {
            pathLookup[key(point[0], point[1])] = true;
        });

        for (y = 0; y < nodes.length; y += 1) {
            for (x = 0; x < nodes[y].length; x += 1) {
                var node = nodes[y][x];
                var wasExplored = !!(node.opened || node.closed || node.tested);
                if (wasExplored && !pathLookup[key(x, y)]) {
                    explored.push([x, y]);
                }
            }
        }

        return explored;
    }

    function gridToScenario(grid, start, end) {
        if (!Array.isArray(grid) || !Array.isArray(grid[0])) {
            throw new Error('grid must be a 2D matrix');
        }

        var height = grid.length;
        var width = grid[0].length;
        var walls = [];

        for (var y = 0; y < height; y += 1) {
            for (var x = 0; x < width; x += 1) {
                if (grid[y][x]) {
                    walls.push([x, y]);
                }
            }
        }

        return {
            width: width,
            height: height,
            walls: walls,
            start: [start.x, start.y],
            end: [end.x, end.y]
        };
    }

    function scenarioToGrid(scenario) {
        var matrix = createMatrix(scenario.width, scenario.height);

        scenario.walls.forEach(function(point) {
            matrix[point[1]][point[0]] = 1;
        });

        matrix[scenario.start[1]][scenario.start[0]] = 0;
        matrix[scenario.end[1]][scenario.end[0]] = 0;
        return matrix;
    }

    function applyScenarioToBuilder(builder, scenario) {
        var matrix = scenarioToGrid(scenario);

        builder.setGrid(matrix);
        builder.placeStart(scenario.start[0], scenario.start[1]);
        builder.placeEnd(scenario.end[0], scenario.end[1]);
    }

    function createScenarioRuntime(options) {
        options = options || {};

        var PF = options.PF || defaultPF;
        var scorer = options.scorer || defaultScorer;
        var persistence = options.persistence || defaultPersistence;

        if (!PF || !scorer || !persistence) {
            throw new Error('Scenario runtime requires PF, scorer, and persistence dependencies');
        }

        return {
            runScenario: function(input) {
                input = input || {};

                var algorithm = input.algorithm || 'AStarFinder';
                var start = input.start || {x: 0, y: 0};
                var end = input.end || {x: 0, y: 0};
                var matrix = clone(input.grid || []);
                var finder = createFinder(PF, algorithm);
                var pfGrid = new PF.Grid(matrix);
                var startedAt = Date.now();
                var path = finder.findPath(start.x, start.y, end.x, end.y, pfGrid);
                var timeMs = Date.now() - startedAt;
                var exploredNodes = collectExploredNodes(pfGrid, path);
                var metrics = scorer.captureMetrics({
                    exploredNodes: exploredNodes,
                    path: path,
                    timeMs: timeMs
                });

                return {
                    algorithm: algorithm,
                    start: {x: start.x, y: start.y},
                    end: {x: end.x, y: end.y},
                    grid: matrix,
                    path: path,
                    exploredNodes: exploredNodes,
                    metrics: metrics
                };
            },

            gridToScenario: function(grid, start, end) {
                return gridToScenario(grid, start, end);
            },

            scenarioToGrid: function(scenario) {
                return scenarioToGrid(scenario);
            },

            applyScenarioToBuilder: function(builder, scenario) {
                applyScenarioToBuilder(builder, scenario);
            },

            saveRun: function(run, scenario) {
                return scorer.saveRun({
                    algorithm: run.algorithm,
                    mapState: scenario,
                    metrics: run.metrics
                });
            },

            getSavedRuns: function() {
                return scorer.getSavedRuns();
            },

            clearRuns: function() {
                scorer.clearRuns();
            },

            compareRuns: function(runIds) {
                return scorer.compareRuns(runIds);
            },

            saveScenario: function(scenario) {
                return persistence.saveScenario(scenario);
            },

            loadScenario: function(serialized) {
                return persistence.loadScenario(serialized);
            },

            getPresets: function() {
                return persistence.getPresets();
            },

            loadPreset: function(name) {
                return persistence.loadPreset(name);
            }
        };
    }

    return createScenarioRuntime;
}));

var createScenarioRuntime = require('../../visual/scenario/runtime');
var createScenarioBuilder = require('../../visual/scenario/scenario-builder');

describe('Scenario integration runtime', function() {
    var runtime;

    beforeEach(function() {
        runtime = createScenarioRuntime();
        runtime.clearRuns();
    });

    it('runs algorithm, captures metrics, persists run, and reloads scenario', function() {
        var preset = runtime.loadPreset('Bottleneck');
        var matrix = runtime.scenarioToGrid(preset);

        var result = runtime.runScenario({
            algorithm: 'AStarFinder',
            grid: matrix,
            start: {x: preset.start[0], y: preset.start[1]},
            end: {x: preset.end[0], y: preset.end[1]}
        });

        result.path.length.should.be.above(0);
        result.metrics.pathLength.should.equal(result.path.length);
        result.metrics.nodesExplored.should.be.above(0);

        var saved = runtime.saveRun(result, preset);
        saved.id.should.equal(1);

        var runs = runtime.getSavedRuns();
        runs.should.have.length(1);
        runs[0].metrics.pathLength.should.equal(result.path.length);

        var serialized = runtime.saveScenario(preset);
        var loaded = runtime.loadScenario(serialized);
        loaded.should.eql(preset);
    });

    it('supports full integration flow: preset -> builder -> run -> score -> save -> compare -> load', function() {
        var preset = runtime.loadPreset('Maze');
        var builder = createScenarioBuilder({width: preset.width, height: preset.height});

        runtime.applyScenarioToBuilder(builder, preset);

        var first = runtime.runScenario({
            algorithm: 'AStarFinder',
            grid: builder.getGrid(),
            start: builder.getStart(),
            end: builder.getEnd()
        });

        first.path.should.be.an.Array();
        first.metrics.should.have.properties('nodesExplored', 'pathLength', 'timeMs');
        first.metrics.pathLength.should.equal(first.path.length);

        var firstSaved = runtime.saveRun(
            first,
            runtime.gridToScenario(first.grid, first.start, first.end)
        );

        var second = runtime.runScenario({
            algorithm: 'DijkstraFinder',
            grid: builder.getGrid(),
            start: builder.getStart(),
            end: builder.getEnd()
        });

        var secondSaved = runtime.saveRun(
            second,
            runtime.gridToScenario(second.grid, second.start, second.end)
        );

        var savedRuns = runtime.getSavedRuns();
        savedRuns.should.have.length(2);
        savedRuns[0].id.should.equal(firstSaved.id);
        savedRuns[1].id.should.equal(secondSaved.id);

        var comparison = runtime.compareRuns([firstSaved.id, secondSaved.id]);
        comparison.baseRunId.should.equal(firstSaved.id);
        comparison.runs.length.should.equal(2);
        comparison.differences[secondSaved.id].should.have.properties(
            'nodesExplored',
            'pathLength',
            'timeMs'
        );

        var scenario = runtime.gridToScenario(builder.getGrid(), builder.getStart(), builder.getEnd());
        var serialized = runtime.saveScenario(scenario);
        var loaded = runtime.loadScenario(serialized);
        loaded.should.eql(scenario);
    });

    it('persists a saved run and reloads its map state through scenario persistence', function() {
        var preset = runtime.loadPreset('Spiral');
        var grid = runtime.scenarioToGrid(preset);

        var run = runtime.runScenario({
            algorithm: 'BiAStarFinder',
            grid: grid,
            start: {x: preset.start[0], y: preset.start[1]},
            end: {x: preset.end[0], y: preset.end[1]}
        });

        run.path.should.be.an.Array();

        var runScenario = runtime.gridToScenario(run.grid, run.start, run.end);
        var savedRun = runtime.saveRun(run, runScenario);
        var savedRuns = runtime.getSavedRuns();

        savedRun.id.should.equal(1);
        savedRuns.should.have.length(1);
        savedRuns[0].mapState.should.eql(runScenario);
        savedRuns[0].metrics.pathLength.should.equal(run.path.length);

        var serialized = runtime.saveScenario(savedRuns[0].mapState);
        var loaded = runtime.loadScenario(serialized);
        loaded.should.eql(runScenario);
    });
});

var fs = require('fs');
var path = require('path');
var vm = require('vm');
var should = require('should');

function runMain(svgSupported) {
    var source = fs.readFileSync(path.resolve(__dirname, '../../visual/js/main.js'), 'utf8');
    var callOrder = [];
    var selectStartBound = false;
    var prevented = false;
    var assignedLocation = null;
    var readyHandler;

    var context = {
        document: {},
        window: {
            set location(value) {
                assignedLocation = value;
            },
            get location() {
                return assignedLocation;
            }
        },
        Raphael: { svg: svgSupported },
        Panel: {
            init: function() {
                callOrder.push('panel.init');
            }
        },
        Controller: {
            init: function() {
                callOrder.push('controller.init');
            }
        }
    };

    context.$ = function(selector) {
        if (selector === context.document) {
            return {
                ready: function(handler) {
                    readyHandler = handler;
                }
            };
        }
        if (selector === context.window) {
            return {
                bind: function(type, handler) {
                    if (type === 'selectstart') {
                        selectStartBound = true;
                        handler({ preventDefault: function() { prevented = true; } });
                    }
                    return this;
                }
            };
        }
        return {
            ready: function(handler) {
                readyHandler = handler;
            },
            bind: function() { return this; }
        };
    };

    vm.runInNewContext(source, context, { filename: 'main.js' });
    readyHandler();

    return {
        callOrder: callOrder,
        assignedLocation: assignedLocation,
        selectStartBound: selectStartBound,
        prevented: prevented
    };
}

describe('visual/main and integration', function() {
    it('should init panel before controller when svg is supported', function() {
        var result = runMain(true);

        should.equal(result.assignedLocation, null);
        result.callOrder.should.eql(['panel.init', 'controller.init']);
        result.selectStartBound.should.equal(true);
        result.prevented.should.equal(true);
    });

    it('should redirect to notsupported page when svg is unavailable', function() {
        var result = runMain(false);

        result.assignedLocation.should.equal('./notsupported.html');
        result.callOrder.should.eql(['panel.init', 'controller.init']);
    });

    it('should keep css hover selector aligned with hide instructions id', function() {
        var css = fs.readFileSync(path.resolve(__dirname, '../../visual/css/style.css'), 'utf8');

        css.indexOf('#hide_instructions:hover').should.be.above(-1);
    });
});
